### Help & Guidance System
```tsx
interface HelpSystem {
  contextual_help: {
    tooltips: 'hover-for-explanation';
    guided_tours: 'step-by-step-walkthrough';
    video_tutorials: 'embedded-explanations';
  };

  error_recovery: {
    helpful_messages: 'actionable-guidance';
    suggested_actions: 'next-step-recommendations';
    contact_support: 'easy-access-help';
  };
}
```

